import '@testing-library/jest-dom';

// Polyfills pour les APIs manquantes
global.TextEncoder = require('util').TextEncoder;
global.TextDecoder = require('util').TextDecoder;

// Mock pour window.matchMedia
Object.defineProperty(window, 'matchMedia', {
  writable: true,
  value: jest.fn().mockImplementation(query => ({
    matches: false,
    media: query,
    onchange: null,
    addListener: jest.fn(),
    removeListener: jest.fn(),
    addEventListener: jest.fn(),
    removeEventListener: jest.fn(),
    dispatchEvent: jest.fn(),
  })),
});

// Mock pour ResizeObserver
global.ResizeObserver = jest.fn().mockImplementation(() => ({
  observe: jest.fn(),
  unobserve: jest.fn(),
  disconnect: jest.fn(),
}));

// Mock pour IntersectionObserver
global.IntersectionObserver = jest.fn().mockImplementation(() => ({
  observe: jest.fn(),
  unobserve: jest.fn(),
  disconnect: jest.fn(),
}));

// Mock pour crypto
const mockSubtle = {
  importKey: jest.fn().mockResolvedValue('mockKey'),
  sign: jest.fn().mockResolvedValue(new Uint8Array([1, 2, 3, 4])),
  verify: jest.fn().mockResolvedValue(true),
  digest: jest.fn().mockResolvedValue(new Uint8Array([1, 2, 3, 4])),
  encrypt: jest.fn().mockResolvedValue(new Uint8Array([1, 2, 3, 4])),
  decrypt: jest.fn().mockResolvedValue(new Uint8Array([1, 2, 3, 4])),
};

global.crypto = {
  subtle: mockSubtle,
  getRandomValues: jest.fn(arr => {
    return arr.map(() => Math.floor(Math.random() * 256));
  }),
};

// Mock pour window.crypto
Object.defineProperty(window, 'crypto', {
  value: global.crypto,
  writable: true
});

// Mock pour performance.now()
if (!global.performance) {
  global.performance = {
    now: jest.fn(() => Date.now()),
  };
}

const { PrismEvents } = require('./__mocks__/prismEvents');

// Mock global prismBus
global.prismBus = {
  emit: jest.fn(),
  on: jest.fn(),
  off: jest.fn(),
  clear: jest.fn(),
  validateEventName: jest.fn(name => name),
  validateEventData: jest.fn(data => data)
};

// Mock fetch
global.fetch = jest.fn(() =>
  Promise.resolve({
    ok: true,
    json: () => Promise.resolve({}),
    text: () => Promise.resolve('')
  })
);

// Mock console methods
global.console = {
  ...console,
  error: jest.fn(),
  warn: jest.fn(),
  log: jest.fn(),
  info: jest.fn(),
  debug: jest.fn()
};

// Mock performance
global.performance = {
  now: jest.fn(() => Date.now()),
  mark: jest.fn(),
  measure: jest.fn()
};

// Clean up after each test
afterEach(() => {
  // Clear all mocks
  jest.clearAllMocks();
  
  // Reset prismBus mock
  global.prismBus.emit.mockClear();
  global.prismBus.on.mockClear();
  global.prismBus.off.mockClear();
  global.prismBus.clear.mockClear();
  
  // Reset fetch mock
  global.fetch.mockClear();
  
  // Reset console mocks
  global.console.error.mockClear();
  global.console.warn.mockClear();
  global.console.log.mockClear();
  global.console.info.mockClear();
  global.console.debug.mockClear();
}); 